namespace optiling {

// UB budget: one tile = tileRows * rowLen floats (input) + temp buffer + output int64.
// temp buffer size ~ (rowLen/64 + 1) * 2 floats rounded up.
static constexpr uint32_t UB_BUDGET_BYTES = 192 * 1024;
static constexpr uint32_t ALIGN_ELEMS = 256;

static inline uint32_t AlignDown(uint32_t x, uint32_t a) {
    return (x / a) * a;
}
static inline uint32_t CeilDiv(uint32_t a, uint32_t b) {
    return (a + b - 1u) / b;
}

static ge::graphStatus TilingFunc(gert::TilingContext *context) {
    ArgmaxOverADimensionCustomTilingData tiling;
    const gert::Shape *inShape = context->GetInputShape(0);
    const int32_t dim = static_cast<const int32_t *>(
        context->GetAttrs()->GetAttrPointer(0))[0];
    int32_t ndim = inShape->GetDimNum();
    uint32_t totalRows = 1;
    uint32_t rowLen = 1;
    for (int32_t i = 0; i < ndim; ++i) {
        uint32_t s = inShape->GetDim(i);
        if (i == dim) {
            rowLen = s;
        } else {
            totalRows *= s;
        }
    }

    // Determine tileRows: each row needs rowLen floats input + temp buffer (~ rowLen/64*2) + output (8 bytes)
    // Rough: 1 row input = rowLen*4 bytes, temp = rowLen/32*8? Use conservative factor 2*rowLen floats.
    uint32_t bytesPerRow = rowLen * sizeof(float) * 2; // input + temp
    bytesPerRow += sizeof(int64_t); // output
    uint32_t maxRowsInTile = UB_BUDGET_BYTES / bytesPerRow;
    if (maxRowsInTile < 1) maxRowsInTile = 1;
    maxRowsInTile = AlignDown(maxRowsInTile, 1); // no alignment needed
    if (maxRowsInTile > 256) maxRowsInTile = 256; // hard cap for latency

    uint32_t tileRows = maxRowsInTile;
    if (totalRows < tileRows) tileRows = totalRows;

    uint32_t blockDim = CeilDiv(totalRows, tileRows);
    if (blockDim < 8) blockDim = 8;
    if (blockDim > 24) blockDim = 24;

    context->SetBlockDim(blockDim);
    tiling.set_totalRows(totalRows);
    tiling.set_rowLen(rowLen);
    tiling.set_tileRows(tileRows);
    tiling.set_blockDim(blockDim);
    tiling.SaveToBuffer(context->GetRawTilingData()->GetData(),
