constexpr int32_t BUFFER_NUM = 2;
constexpr int32_t MASK_LEN = 64; // for float: 256 bytes / 4 = 64 elements per repeat

class KernelArgmaxOverADimensionCustom {
public:
    __aicore__ inline KernelArgmaxOverADimensionCustom() {}

    __aicore__ inline void Init(GM_ADDR x, GM_ADDR y,
                                uint32_t totalRows, uint32_t rowLen,
                                uint32_t tileRows) {
        totalRows_ = totalRows;
        rowLen_ = rowLen;
        tileRows_ = tileRows;

        xGm_.SetGlobalBuffer((__gm__ float*)x);
        yGm_.SetGlobalBuffer((__gm__ int64_t*)y);

        uint32_t ipB = tileRows_ * rowLen_ * sizeof(float);
        uint32_t opB = tileRows_ * sizeof(int64_t);
        // temp buffer size for ReduceMax (internal)
        uint32_t repeat = (rowLen_ + MASK_LEN - 1) / MASK_LEN;  // number of 64-element repeats
        uint32_t workElems = ((repeat * 2) + 7) / 8 * 8;       // round up to 8 (block of 32B)
        uint32_t tmpB = workElems * sizeof(float);

        pipe_.InitBuffer(inQueueX_, BUFFER_NUM, ipB);
        pipe_.InitBuffer(outQueueY_, BUFFER_NUM, opB);
        pipe_.InitBuffer(tmpQueue_, 1, tmpB);
    }

    __aicore__ inline void Process() {
        if (totalRows_ == 0 || rowLen_ == 0) return;

        uint32_t blockNum = static_cast<uint32_t>(AscendC::GetBlockNum());
        uint32_t blockIdx = static_cast<uint32_t>(AscendC::GetBlockIdx());
        uint32_t strideRows = blockNum * tileRows_;

        uint32_t base = blockIdx * tileRows_;
        if (base >= totalRows_) return;

        uint32_t curRows = totalRows_ - base;
        if (curRows > tileRows_) curRows = tileRows_;

        // Prefetch first tile
        CopyIn(base, curRows);
        while (true) {
            uint32_t nextBase = base + strideRows;
            uint32_t nextRows = 0;
            if (nextBase < totalRows_) {
                nextRows = totalRows_ - nextBase;
                if (nextRows > tileRows_) nextRows = tileRows_;
                CopyIn(nextBase, nextRows);
            }

            Compute(curRows);
            CopyOut(base, curRows);

            if (nextRows == 0) break;
            base = nextBase;
            curRows = nextRows;
        }
    }

private:
    __aicore__ inline void CopyIn(uint32_t rowOffset, uint32_t rows) {
        AscendC::LocalTensor<float> xLocal = inQueueX_.AllocTensor<float>();
        // input is contiguous: each row has rowLen floats, rows are contiguous.
        // offset in floats = rowOffset * rowLen_
        AscendC::DataCopy(xLocal, xGm_[rowOffset * rowLen_], rows * rowLen_);
        inQueueX_.EnQue(xLocal);
    }

    __aicore__ inline void Compute(uint32_t rows) {
        AscendC::LocalTensor<float> xLocal = inQueueX_.DeQue<float>();
        AscendC::LocalTensor<int64_t> yLocal = outQueueY_.AllocTensor<int64_t>();
        AscendC::LocalTensor<float> tmp = tmpQueue_.AllocTensor<float>();

        uint32_t repeat = (rowLen_ + MASK_LEN - 1) / MASK_LEN;
        uint32_t workElems = ((repeat * 2) + 7) / 8 * 8;

        for (uint32_t r = 0; r < rows; ++r) {
            // slice the row
            AscendC::LocalTensor<float> row = xLocal[r * rowLen_];
            AscendC::LocalTensor<float> outLocal = tmp; // reuse tmp as output of ReduceMax (size workElems)
            AscendC::LocalTensor<float> temp = tmp;     // but ReduceMax uses internal buffer
            // We'll use separate pointers inside tmp:
            // outLocal at 0..workElems-1, temp at workElems..2*workElems-1? Actually tmp size is workElems, so we need two buffers.
            // For simplicity, we allocate a separate small tensor internally? We'll use the fact that tmp has workElems,
            // and call ReduceMax with sharedTmpBuffer pointing to the same area but with offset? Not safe.
            // Better: use two buffers: outLocal and sharedTmp. We'll split tmp into two halves.
            // Since tmp size is workElems, we can use outLocal = tmp[0] of size 2 (for max and index) and sharedTmp = tmp[2] of size workElems-2?
            // But ReduceMax expects dst, src, tmp, srcDataSize, withIndex. dst must have space for 2 floats (value,index) or more?
            // Actually in the example they used dstDataSize=16 (32B aligned) and the output is stored in first positions.
            // We'll allocate a separate output tensor with 2 floats.
            AscendC::LocalTensor<float> dstLocal = tmp; // just use first 2 elements, but need enough space
            // Actually tmp is workElems floats, safe to use first 2 for dst.
            AscendC::ReduceMax<float>(dstLocal, row, tmp + 2, rowLen_, true);
            AscendC::PipeBarrier<PIPE_V>();
            // dstLocal[0] = max value, dstLocal[1] = index (float)
            float idxFloat = dstLocal.GetValue(1);
            int64_t idx = static_cast<int64_t>(idxFloat);
            yLocal.SetValue(r, idx);
        }

        tmpQueue_.FreeTensor(tmp);
        outQueueY_.EnQue<int64_t>(yLocal);
        inQueueX_.FreeTensor(xLocal);
    }

    __aicore__ inline void CopyOut(uint32_t rowOffset, uint32_t rows) {
        AscendC::LocalTensor<int64_t> yLocal = outQueueY_.DeQue<int64_t>();
        AscendC::DataCopy(yGm_[rowOffset], yLocal, rows);
        outQueueY_.FreeTensor(yLocal);
    }

private:
    AscendC::TPipe pipe_;
    AscendC::TQue<AscendC::TPosition::VECIN, BUFFER_NUM> inQueueX_;
    AscendC::TQue<AscendC::TPosition::VECOUT, BUFFER_NUM> outQueueY_;
    AscendC::TQue<AscendC::TPosition::VECCALC, 1> tmpQueue_;
    AscendC::GlobalTensor<float> xGm_;
    AscendC::GlobalTensor<int64_t> yGm_;
    uint32_t totalRows_ {0};
    uint32_t rowLen_ {0};
    uint32_t tileRows_ {0};
};

